import { Component, Event, h, Prop, EventEmitter, Element, State, Watch } from '@stencil/core';
import { GalleryImage } from '../../subcomponents/types';
import { ImageErrorIcon, SensitiveEyeIcon, ExpandIcon } from '../../subcomponents/svg/Svg';
import { MOBILE_BREAKPOINT } from '../../constants/breakpoints';

@Component({
  tag: 'image-gallery',
  styleUrl: 'image-gallery.css',
  shadow: true,
})
export class ImageGallery {
  @Element() el: HTMLElement;

  // Props
  @Prop() images: GalleryImage[] = [];
  @Prop() initialImageCount: number = 12;
  @Prop({ mutable: true }) displayedImageCount: number;
  // TODO: Should only be able to configure "image results" part. variables should always be there
  @Prop() resultsTextTemplate: string;
  @Prop() optionalClass: string = '';
  @Prop() galleryId: string = 'image-gallery';
  @Prop() noImagesContent: HTMLElement;
  @Prop() sensitiveImageText: string;
  @Prop() seePhotoText: string;
  @Prop() imageLoadFailedText: string;
  @Prop() reloadButtonText: string;

  // State
  @State() isMobile: boolean = typeof window !== 'undefined' ? window.innerWidth <= MOBILE_BREAKPOINT : false;

  // Events
  @Event() imageClick: EventEmitter<{ image: GalleryImage; index: number }>;

  // Track image loading/error state
  @State() imageLoadStatus: { [key: string]: 'loading' | 'loaded' | 'error' } = {};
  @State() imageRetryCount: { [key: string]: number } = {};
  @State() focusedImageIndex: number = 0;

  private resizeListener: () => void;
  private galleryGridRef: HTMLElement;

  componentWillLoad() {
    if (!this.displayedImageCount) {
      this.displayedImageCount = this.initialImageCount;
    }
    this.setupResizeListener();
  }

  componentDidLoad() {
    if (typeof window !== 'undefined') {
      this.isMobile = window.innerWidth <= MOBILE_BREAKPOINT;
      window.addEventListener('resize', this.resizeListener);
    }
  }

  @Watch('images')
  watchImagesHandler(newImages: GalleryImage[]) {
    if (newImages && newImages.length > 0) {
      // Ensure displayed count doesn't exceed available images
      this.displayedImageCount = Math.min(this.displayedImageCount || this.initialImageCount, newImages.length);
    }
    if (newImages && this.galleryGridRef) {
      this.galleryGridRef.scrollTop = 0;
    }
  }

  disconnectedCallback() {
    if (typeof window !== 'undefined' && this.resizeListener) {
      window.removeEventListener('resize', this.resizeListener);
    }
  }

  private setupResizeListener() {
    this.resizeListener = () => {
      this.isMobile = window.innerWidth <= MOBILE_BREAKPOINT;
    };
  }

  private handleImageClick = (image: GalleryImage, index: number) => {
    this.imageClick.emit({ image, index });
  };

  private getResultsText(): string {
    if (!this.images || this.images.length === 0) {
      return '';
    }
    
    return this.resultsTextTemplate
      .replace('{current}', this.displayedImageCount.toString())
      .replace('{total}', this.images.length.toString());
  }

  // Shuffle Animation
  private positions: Map<string | number, DOMRect> = new Map();

  private capturePositions() {
    if (!this.galleryGridRef) return;
    const items = this.galleryGridRef.querySelectorAll('.gallery-item');
    items.forEach((item: Element) => {
      const key = (item as HTMLElement).getAttribute('data-key');
      if (key) {
        this.positions.set(key, item.getBoundingClientRect());
      }
    });
  }

  private playShuffleAnimation() {
    if (!this.galleryGridRef) return;
    
    // Respect user's motion preferences
    const prefersReducedMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;
    if (prefersReducedMotion) {
      this.positions.clear();
      return;
    }
    
    const items = this.galleryGridRef.querySelectorAll('.gallery-item');
    items.forEach((item: Element) => {
      const key = (item as HTMLElement).getAttribute('data-key');
      if (!key) return;
      const prev = this.positions.get(key);
      const next = item.getBoundingClientRect();
      if (prev) {
        const dx = prev.left - next.left;
        const dy = prev.top - next.top;
        if (dx !== 0 || dy !== 0) {
          (item as HTMLElement).animate([
            { transform: `translate(${dx}px, ${dy}px)` },
            { transform: 'translate(0, 0)' }
          ], {
            duration: 350,
            easing: 'cubic-bezier(0.33, 1, 0.68, 1)'
          });
        }
      }
    });
    this.positions.clear();
  }

  componentWillUpdate() {
    // Capture positions before update for shuffling animation
    this.capturePositions();
  }

  componentDidUpdate() {
    this.playShuffleAnimation();
  }

  private handleImageLoad = (id: string | number) => {
    this.imageLoadStatus = { ...this.imageLoadStatus, [id]: 'loaded' as const };
    this.imageRetryCount = { ...this.imageRetryCount, [id]: 0 };
  };
  
  private handleImageError = (id: string | number) => {
    const currentRetries = this.imageRetryCount[id] || 0;
    const maxRetries = 3;
    
    if (currentRetries < maxRetries) {
      this.imageRetryCount = { ...this.imageRetryCount, [id]: currentRetries + 1 };
      this.imageLoadStatus = { ...this.imageLoadStatus, [id]: 'loading' as const };

      // Delay the retry slightly to avoid immediate failure
      setTimeout(() => {
        const imgElement = this.el.shadowRoot?.querySelector(`img[data-image-id="${id}"]`) as HTMLImageElement;
        if (imgElement) {
          const originalSrc = imgElement.src;
          imgElement.src = '';
          setTimeout(() => {
            imgElement.src = originalSrc;
          }, 100);
        }
      }, 500);
    } else {
      this.imageLoadStatus = { ...this.imageLoadStatus, [id]: 'error' as const };
    }
  };
  
  private handleRetryClick = (id: string | number, imageSrc: string) => {
    this.imageRetryCount = { ...this.imageRetryCount, [id]: 0 };
    this.imageLoadStatus = { ...this.imageLoadStatus, [id]: 'loading' as const };
    
    setTimeout(() => {
      const imgElement = this.el.shadowRoot?.querySelector(`img[data-image-id="${id}"]`) as HTMLImageElement;
      if (imgElement) {
        imgElement.src = imageSrc;
      }
    }, 100);
  };

  private handleImageKeyDown = (event: KeyboardEvent, image: GalleryImage, index: number) => {
    const key = event.key;
    
    // Handle Escape to exit gallery focus
    if (key === 'Escape') {
      event.preventDefault();
      (event.target as HTMLElement).blur();
      return;
    }
    
    // Handle Enter and Space for interaction
    if (key === 'Enter' || key === ' ') {
      event.preventDefault();
      this.handleImageClick(image, index);
      return;
    }

    // Handle Arrow key navigation within the gallery
    if (key.startsWith('Arrow')) {
      event.preventDefault();
      const displayedImages = this.images.slice(0, this.displayedImageCount);
      const totalImages = displayedImages.length;
      const cols = this.isMobile ? 2 : 3;
      let newIndex = index;

      switch (key) {
        case 'ArrowRight':
          newIndex = Math.min(index + 1, totalImages - 1);
          break;
        case 'ArrowLeft':
          newIndex = Math.max(index - 1, 0);
          break;
        case 'ArrowDown':
          newIndex = Math.min(index + cols, totalImages - 1);
          break;
        case 'ArrowUp':
          newIndex = Math.max(index - cols, 0);
          break;
      }

      if (newIndex !== index) {
        this.focusedImageIndex = newIndex;
        // Focus the new image
        setTimeout(() => {
          const galleryItems = this.el.shadowRoot?.querySelectorAll('.gallery-item');
          if (galleryItems && galleryItems[newIndex]) {
            (galleryItems[newIndex] as HTMLElement).focus();
          }
        }, 0);
      }
    }
  };

  private renderImageGrid() {
    const displayedImages = this.images.slice(0, this.displayedImageCount);
    return (
      <div
        class={`gallery-grid ${this.isMobile ? 'mobile-grid' : 'desktop-grid'}`}
        aria-label={`Image gallery with ${this.displayedImageCount} images.`}
        ref={el => (this.galleryGridRef = el as HTMLElement)}
      >
        {displayedImages.map((image, index) => {
          const key = image.id || index;
          const status = this.imageLoadStatus[key] || 'loading';

          // Determine which image variant to use based on container size
          // Thumbnail: 160x120, Standard: 308x231, Full: 936x702
          let src = image.urlFull;
          if (this.galleryGridRef) {
            const gridCols = this.isMobile ? 2 : 3;
            const displayWidth = this.galleryGridRef.offsetWidth / gridCols;
            
            if (displayWidth <= 160 && image.urlThumbnail) {
              src = image.urlThumbnail;
            } else if (displayWidth <= 308 && image.urlStandard) {
              src = image.urlStandard;
            }
            // For displayWidth > 308, we already have urlFull as default
          }

          return (
            <div
              key={key}
              data-key={key}
              class={`gallery-item${status === 'loading' ? ' loading' : ''}`}
              tabindex="0"
              onClick={() => status === 'loaded' && this.handleImageClick(image, index)}
              onKeyDown={(e) => status === 'loaded' && this.handleImageKeyDown(e, image, index)}
              onFocus={() => { this.focusedImageIndex = index; }}
              aria-label={`${image.alt}${image.sensitive ? `, ${this.sensitiveImageText.toLowerCase()}` : ''}${status === 'loading' ? ', loading' : status === 'error' ? ', failed to load' : ', loaded'}.`}
            >
              <div 
                class={`image-container${status === 'error' ? ' image-error' : ''}${status === 'loaded' ? ' loaded' : ''}${status === 'loading' ? ' loading' : ''}`} 
                style={{ 
                  '--image-url': status !== 'error' ? `url(${src})` : ''
                }}
              >
                {status !== 'error' && !image.sensitive && (
                  <img
                    src={src}
                    alt={image.alt}
                    data-image-id={image.id}
                    class={`${status === 'loaded' ? 'loaded' : 'loading'}`}
                    onLoad={() => this.handleImageLoad(image.id)}
                    onError={() => this.handleImageError(image.id)}
                  />
                )}
                {status !== 'error' && image.sensitive && (
                  <div>
                    <img
                      src={src}
                      alt={image.alt}
                      data-image-id={image.id}
                      class={`${status === 'loaded' ? 'loaded' : 'loading'} sensitive-image`}
                      style={{ opacity: status === 'loaded' ? '0' : '1' }}
                      onLoad={() => this.handleImageLoad(image.id)}
                      onError={() => this.handleImageError(image.id)}
                    />
                    {status === 'loaded' && (
                      <div class="sensitive-overlay">
                        <div class="sensitive-blur"></div>
                        <div class="sensitive-eye-text-container">
                          <SensitiveEyeIcon className="sensitive-eye-icon" />
                          <div class="sensitive-text">{this.sensitiveImageText}</div>
                        </div>
                        <div class="sensitive-action-text">{this.seePhotoText}</div>
                      </div>
                    )}
                  </div>
                )}
                {status === 'loaded' && !image.sensitive && (
                  <div class="touch-expand-button">
                    <ExpandIcon className="expand-icon" />
                  </div>
                )}
                {status === 'error' && (
                  <div class="error-state-content">
                    <ImageErrorIcon className="error-icon" />
                    <div class="error-state-text">
                      {this.imageLoadFailedText}
                    </div>
                    <button
                      type="button"
                      class="error-retry-button"
                      tabindex="0"
                      onClick={(e) => {
                        e.stopPropagation();
                        this.handleRetryClick(key, src);
                      }}
                      onKeyDown={(e) => {
                        if (e.key === 'Enter' || e.key === ' ') {
                          e.stopPropagation();
                          e.preventDefault();
                          this.handleRetryClick(key, src);
                        }
                      }}
                      aria-label="Retry loading image"
                    >
                      {this.reloadButtonText}
                    </button>
                  </div>
                )}
              </div>
            </div>
          );
        })}
      </div>
    );
  }

  render() {
    const hasImages = this.images && this.images.length > 0;

    return (
      <div 
        class={`image-gallery-container ${this.optionalClass}`}
        id={this.galleryId}
        role="region"
        aria-label="Image gallery"
      >
        {hasImages ? (
          [
            this.renderImageGrid(),
            <div class="results-text" aria-live="polite" aria-atomic="true">
              {this.getResultsText()}
            </div>
          ]
        ) : (
          <div class="no-images-state" innerHTML={ this.noImagesContent?.innerHTML }></div>
        )}
      </div>
    );
  }
}